def is_hall_of_famer(player_name):
    hall_of_famers = {
        "Phil Housley", "Gilbert Perreault", "Pierre Turgeon"
    }
    return player_name in hall_of_famers

# Example usage:
print(is_hall_of_famer("Gilbert Perreault"))  # Output: True
print(is_hall_of_famer("Rasmus Dahlin"))     # Output: False
